import subprocess
import sys

dims = []
for w in range(12, 25):
    for h in range(6, w + 1):
        for d in range(6, h + 1):
            vol = w * h * d
            if 1004 <= vol < 1440:
                dims.append((vol, w, h, d))

dims.sort()

for vol, w, h, d in dims:
    print(f"Testing {w}x{h}x{d} (vol {vol})...", flush=True)
    res = subprocess.run(["python3", "solver.py", str(w), str(h), str(d)], capture_output=True, text=True)
    if "Found solution" in res.stdout:
        print(f"\nFound better solution: {w}x{h}x{d} (vol {vol})")
        sys.exit(0)
    else:
        print(f" No ({res.stdout.strip().split()[-1] if res.stdout.strip() else 'error'})")
